<template>
  <div>
    <el-col :span="6" style="float: right;margin-bottom: 5px" >
      <el-input v-model="filters[0].value" placeholder="search..."/>
    </el-col>
    <data-tables v-if="!loading" :data="projectInfo" :filters="filters" :table-props="props">
      <el-table-column v-for="title in titles" :prop="title.prop" :label="title.label" :key="title.prop" sortable="custom"/>
    </data-tables>
  </div>
</template>

<style>
  .el-table .warning-row {
    background: #f0ad4e;
    color: white;
  }

  .el-table .warning-row:hover {
    color: black;
  }

  .el-table .success-row {
    background: lightgreen;
    color: white;
  }

  .el-table .success-row:hover {
    color: black;
  }

  .el-table .bad-row {
    background: #d9534f;
    color: white;
  }

  .el-table .bad-row:hover {
    color: black;
  }
</style>

<script>
import { mapActions, mapGetters } from 'vuex'

function selectClassName({ row, rowIndex }) {
  if (row.percentage >= 75) {
    return 'success-row'
  } else if (row.percentage >= 35) {
    return 'warning-row'
  } else {
    return 'bad-row'
  }
}
export default {
  data() {
    return {
      loading: true,
      props: {
        'row-class-name': selectClassName
      },
      titles: [{
        prop: 'projectName',
        label: 'Project Name'
      }, {
        prop: 'percentage',
        label: 'Percentage'
      }, {
        prop: 'totalUsage',
        label: 'Total Usage'
      }, {
        prop: 'totalAutomation',
        label: 'Total Automation'
      }],
      filters: [
        {
          value: '',
          filterFn: (row, filter) => {
            return Object.keys(row).some(prop => {
              return (JSON.stringify(row[prop]) + '').trim().toLowerCase().indexOf(filter.value.trim().toLowerCase()) > -1
            })
          }
        }
      ]
    }
  },
  computed: {
    ...mapGetters('automationUsage', ['projectInfo'])
  },
  mounted() {
    this.getProjectInfo().then((value) => {
      this.loading = false
    })
  },
  methods: {
    ...mapActions('automationUsage', ['getProjectInfo'])
  }
}
</script>
